/* MARKDOWN */
function MdText({text}){if(!text)return null;const lines=text.split("\n");return <>{lines.map((line,i)=>{let h=line.replace(/\*\*(.+?)\*\*/g,'<strong style="color:'+B.white+'">$1</strong>').replace(/\*(.+?)\*/g,'<em>$1</em>').replace(/`(.+?)`/g,'<code style="background:rgba(0,230,118,0.1);padding:1px 5px;border-radius:4px;font-size:12px;color:'+B.green+'">$1</code>');if(line.startsWith("- ")||line.startsWith("• "))h='<span style="color:'+B.green+';margin-right:6px">•</span>'+h.slice(2);return <div key={i} style={{marginBottom:line.trim()?4:8}} dangerouslySetInnerHTML={{__html:h||"&nbsp;"}}/>;})}</>;}

